import{_ as e,o as a,c as l,a2 as o}from"./chunks/framework.Pywvta2k.js";const g=JSON.parse('{"title":"河间学派·刘完素","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/03-宋金元/02-河间学派（刘完素）.md","filePath":"tcm-data/03-宋金元/02-河间学派（刘完素）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/03-宋金元/02-河间学派（刘完素）.md"};function n(s,t,i,d,h,u){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="河间学派·刘完素" tabindex="-1">河间学派·刘完素 <a class="header-anchor" href="#河间学派·刘完素" aria-label="Permalink to &quot;河间学派·刘完素&quot;">​</a></h1><blockquote><p>刘完素（约1110-1200年），河北河间人 金元四大家之首，&quot;寒凉派&quot;创始人 代表作：《素问玄机原病式》《宣明论方》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字守真，号河间居士</li><li><strong>生平</strong>：因母亲病逝而立志学医，刻苦钻研《内经》20余年</li><li><strong>学术地位</strong>：金元四大家之首，**&quot;火热论&quot;**的倡导者</li><li><strong>与张元素的关系</strong>：张元素曾治愈刘完素的伤寒病，两人相互敬重</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-火热论" tabindex="-1">1. 火热论 <a class="header-anchor" href="#_1-火热论" aria-label="Permalink to &quot;1. 火热论&quot;">​</a></h3><blockquote><p><strong>「六气皆从火化。」</strong></p></blockquote><p>刘完素认为：风、寒、暑、湿、燥、火六气中，<strong>火热是致病的最主要因素</strong>。其他五气在病理状态下都会转化为火热。</p><h3 id="_2-五运六气与疾病" tabindex="-1">2. 五运六气与疾病 <a class="header-anchor" href="#_2-五运六气与疾病" aria-label="Permalink to &quot;2. 五运六气与疾病&quot;">​</a></h3><p>刘完素特别重视五运六气对疾病的影响，认为治疗必须考虑当年运气。</p><h3 id="_3-降心火、益肾水" tabindex="-1">3. 降心火、益肾水 <a class="header-anchor" href="#_3-降心火、益肾水" aria-label="Permalink to &quot;3. 降心火、益肾水&quot;">​</a></h3><blockquote><p><strong>「泻心火则肺金不伤，补肾水则心火自降。」</strong></p></blockquote><p>这一思想被朱震亨继承发展为&quot;泻南补北&quot;法。</p><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>防风通圣散</strong></td><td style="text-align:left;">防风、荆芥、麻黄、薄荷、大黄、芒硝、栀子、石膏、黄芩、连翘、桔梗、当归、川芎、白芍、白术、甘草、滑石</td><td style="text-align:left;">表里俱实（风热+便秘）</td></tr><tr><td style="text-align:left;"><strong>双解散</strong></td><td style="text-align:left;">防风通圣散+天水散</td><td style="text-align:left;">表里俱热</td></tr><tr><td style="text-align:left;"><strong>天水散</strong>（六一散）</td><td style="text-align:left;">滑石、甘草（6:1）</td><td style="text-align:left;">暑湿、小便不利</td></tr><tr><td style="text-align:left;"><strong>黄连解毒汤</strong></td><td style="text-align:left;">黄连、黄芩、黄柏、栀子</td><td style="text-align:left;">三焦火毒</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「六气皆从火化。」</strong></p></blockquote><blockquote><p><strong>「五运六气，临证之要。」</strong></p></blockquote><blockquote><p><strong>「降心火，益肾水。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li>开创了金元医学争鸣的先河</li><li>&quot;火热论&quot;影响了温病学派</li><li>防风通圣散至今是治疗表里俱实证的常用方</li></ul><h3 id="与黄元御的对比" tabindex="-1">与黄元御的对比 <a class="header-anchor" href="#与黄元御的对比" aria-label="Permalink to &quot;与黄元御的对比&quot;">​</a></h3><p>刘完素认为&quot;火热为病最多&quot;，黄元御认为&quot;水寒土湿为病最多&quot;——<strong>两人的时代背景不同</strong>（刘完素见温热病多，黄元御见寒湿证多），临床上需根据患者具体症状选择框架。</p><hr><p><em>本条目为精简框架版。可扩展至寒凉派与温补派的对比分析。</em></p>',30)])])}const q=e(r,[["render",n]]);export{g as __pageData,q as default};
